using Microsoft.JSInterop;
using SiteInspector.Models;

namespace SiteInspector.Services;

public class IndexedDbService
{
    private readonly IJSRuntime _js;
    private bool _initialized;

    public IndexedDbService(IJSRuntime js)
    {
        _js = js;
    }

    public async Task InitAsync()
    {
        if (_initialized) return;
        await _js.InvokeVoidAsync("indexedDb.init");
        _initialized = true;
    }

    public async Task SaveInspectionAsync(Inspection inspection)
    {
        await InitAsync();
        await _js.InvokeVoidAsync("indexedDb.saveInspection", inspection);
    }

    public async Task<List<Inspection>> GetAllInspectionsAsync()
    {
        await InitAsync();
        return await _js.InvokeAsync<List<Inspection>>("indexedDb.getAllInspections") ?? new();
    }

    public async Task<Inspection?> GetInspectionAsync(Guid id)
    {
        await InitAsync();
        return await _js.InvokeAsync<Inspection?>("indexedDb.getInspection", id.ToString());
    }

    public async Task DeleteInspectionAsync(Guid id)
    {
        await InitAsync();
        await _js.InvokeVoidAsync("indexedDb.deleteInspection", id.ToString());
    }

    public async Task SavePhotoAsync(PhotoRecord photo)
    {
        await InitAsync();
        await _js.InvokeVoidAsync("indexedDb.savePhoto", photo);
    }

    public async Task<List<PhotoRecord>> GetPhotosForInspectionAsync(Guid inspectionId)
    {
        await InitAsync();
        return await _js.InvokeAsync<List<PhotoRecord>>("indexedDb.getPhotosForInspection", inspectionId.ToString()) ?? new();
    }

    public async Task<List<Inspection>> GetPendingInspectionsAsync()
    {
        await InitAsync();
        return await _js.InvokeAsync<List<Inspection>>("indexedDb.getPendingInspections") ?? new();
    }
}
