```razor
@page "/checklist/{InspectionId:guid}"
@inject IndexedDbService Db
@inject NavigationManager Navigation

@if (inspection == null)
{
    <p>Loading...</p>
}
else
{
    <div class="progress-text">@reviewedCount / @totalCount items reviewed</div>
    <div class="progress-bar">
        <div class="progress-fill" style="width: @ProgressPercent%"></div>
    </div>

    <div class="category-tabs">
        @foreach (var cat in categories)
        {
            <button class="category-tab @(cat == activeCategory ? "active" : "")"
                    @onclick="() => SetCategory(cat)">
                @cat
            </button>
        }
    </div>

    @foreach (var item in ActiveItems)
    {
        <div class="checklist-item">
            <div class="checklist-item-desc">@item.Description</div>
            <div class="checklist-buttons">
                <button class="check-btn @(item.IsCompliant == true ? "pass" : "")"
                        @onclick="() => SetCompliance(item, true)">✓</button>
                <button class="check-btn @(item.IsCompliant == false ? "fail" : "")"
                        @onclick="() => SetCompliance(item, false)">✗</button>
                <button class="check-btn @(item.IsCompliant == null && itemTouched.Contains(item.Id) ? "na" : "")"
                        @onclick="() => SetNA(item)">N/A</button>
            </div>
            <div class="item-notes">
                <input placeholder="Notes (optional)" value="@item.Notes"
                       @onchange="(e) => SetNotes(item, e.Value?.ToString() ?? "")" />
            </div>
        </div>
    }

    <div style="display:flex;gap:8px;margin-top:16px;">
        @if (categoryIndex > 0)
        {
            <button class="btn btn-secondary" style="flex:1;" @onclick="PrevCategory">← Previous</button>
        }
        @if (categoryIndex < categories.Count - 1)
        {
            <button class="btn btn-primary" style="flex:1;" @onclick="NextCategory">Next →</button>
        }
        else
        {
            <button class="btn btn-success" style="flex:1;" @onclick="GoToPhotos">📷 Photos →</button>
        }
    </div>
}

@code {
    [Parameter] public Guid InspectionId { get; set; }

    private Inspection? inspection;
    private List<string> categories = new();
    private string activeCategory = "";
    private int categoryIndex;
    private HashSet<Guid> itemTouched = new();

    private List<ChecklistItem> ActiveItems =>
        inspection?.ChecklistItems.Where(i => i.Category == activeCategory).ToList() ?? new();

    private int reviewedCount => inspection?.ChecklistItems.Count(i => i.IsCompliant != null || itemTouched.Contains(i.Id)) ?? 0;
    private int totalCount => inspection?.ChecklistItems.Count ?? 0;
    private double ProgressPercent => totalCount > 0 ? (double)reviewedCount / totalCount * 100 : 0;

    protected override async Task OnInitializedAsync()
    {
        inspection = await Db.GetInspectionAsync(InspectionId);
        if (inspection != null)
        {
            categories = inspection.ChecklistItems.Select(i => i.Category).Distinct().ToList();
            if (categories.Any())
            {
                activeCategory = categories[0];
            }
        }
    }

    private void SetCategory(string category)
    {
        activeCategory = category;
        categoryIndex = categories.IndexOf(category);
    }

    private async Task SetCompliance(ChecklistItem item, bool compliant)
    {
        item.IsCompliant = compliant;
        itemTouched.Add(item.Id);
        await SaveInspection();
    }

    private async Task SetNA(ChecklistItem item)
    {
        item.IsCompliant = null;
        itemTouched.Add(item.Id);
        await SaveInspection();
    }

    private async Task SetNotes(ChecklistItem item, string notes)
    {
        item.Notes = notes;
        await SaveInspection();
    }

    private async Task SaveInspection()
    {
        if (inspection != null)
        {
            await Db.SaveInspectionAsync(inspection);
        }
    }

    private void NextCategory()
    {
        if (categoryIndex < categories.Count - 1)
        {
            categoryIndex++;
            activeCategory = categories[categoryIndex];
        }
    }

    private void PrevCategory()
    {
        if (categoryIndex > 0)
        {
            categoryIndex--;
            activeCategory = categories[categoryIndex];
        }
    }

    private void GoToPhotos()
    {
        Navigation.NavigateTo($"/photos/{InspectionId}");
    }
}
