using SiteInspector.Models;

namespace SiteInspector.Services;

public class SyncService : IDisposable
{
    private readonly IndexedDbService _db;
    private readonly ConnectivityService _connectivity;
    private readonly HttpClient _http;
    private Timer? _timer;
    public event Action<string>? OnSyncStatusChanged;
    public bool IsSyncing { get; private set; }

    public SyncService(IndexedDbService db, ConnectivityService connectivity, HttpClient http)
    {
        _db = db;
        _connectivity = connectivity;
        _http = http;
    }

    public void Start()
    {
        _connectivity.OnConnectivityChanged += HandleConnectivityChange;
        _timer = new Timer(async _ => await TrySyncAsync(), null, TimeSpan.FromSeconds(30), TimeSpan.FromSeconds(60));
    }

    private async void HandleConnectivityChange(bool isOnline)
    {
        if (isOnline)
        {
            await TrySyncAsync();
        }
    }

    public async Task TrySyncAsync()
    {
        if (IsSyncing || !_connectivity.IsOnline) return;

        try
        {
            IsSyncing = true;
            OnSyncStatusChanged?.Invoke("Syncing...");

            var pending = await _db.GetPendingInspectionsAsync();
            foreach (var inspection in pending)
            {
                try
                {
                    // In a real app, this would POST to an API
                    // For now, mark as synced after a simulated delay
                    await Task.Delay(500);
                    inspection.Status = InspectionStatus.Synced;
                    await _db.SaveInspectionAsync(inspection);
                }
                catch
                {
                    // Will retry on next cycle
                }
            }

            OnSyncStatusChanged?.Invoke(pending.Count > 0 ? $"Synced {pending.Count} inspection(s)" : "Up to date");
        }
        catch
        {
            OnSyncStatusChanged?.Invoke("Sync failed, will retry");
        }
        finally
        {
            IsSyncing = false;
        }
    }

    public void Dispose()
    {
        _connectivity.OnConnectivityChanged -= HandleConnectivityChange;
        _timer?.Dispose();
    }
}

window.indexedDb = {
    db: null,

    init: function () {
        return new Promise((resolve, reject) => {
            if (this.db) { resolve(); return; }
            const request = window.indexedDB.open("SiteInspectorDb", 1);
            request.onupgradeneeded = (e) => {
                const db = e.target.result;
                if (!db.objectStoreNames.contains("inspections")) {
                    db.createObjectStore("inspections", { keyPath: "id" });
                }
                if (!db.objectStoreNames.contains("photos")) {
                    const photoStore = db.createObjectStore("photos", { keyPath: "id" });
                    photoStore.createIndex("inspectionId", "inspectionId", { unique: false });
                }
            };
            request.onsuccess = (e) => {
                this.db = e.target.result;
                resolve();
            };
            request.onerror = (e) => reject(e.target.error);
        });
    },

    saveInspection: function (inspection) {
        return new Promise((resolve, reject) => {
            const tx = this.db.transaction("inspections", "readwrite");
            const store = tx.objectStore("inspections");
            // Convert C# PascalCase to storage format - store as-is since JS interop handles it
            store.put(inspection);
            tx.oncomplete = () => resolve();
            tx.onerror = (e) => reject(e.target.error);
        });
    },

    getAllInspections: function () {
        return new Promise((resolve, reject) => {
            const tx = this.db.transaction("inspections", "readonly");
            const store = tx.objectStore("inspections");
            const request = store.getAll();
            request.onsuccess = () => resolve(request.result || []);
            request.onerror = (e) => reject(e.target.error);
        });
    },

    getInspection: function (id) {
        return new Promise((resolve, reject) => {
            const tx = this.db.transaction("inspections", "readonly");
            const store = tx.objectStore("inspections");
            const request = store.get(id);
            request.onsuccess = () => resolve(request.result || null);
            request.onerror = (e) => reject(e.target.error);
        });
    },

    deleteInspection: function (id) {
        return new Promise((resolve, reject) => {
            const tx = this.db.transaction("inspections", "readwrite");
            const store = tx.objectStore("inspections");
            store.delete(id);
            tx.oncomplete = () => resolve();
            tx.onerror = (e) => reject(e.target.error);
        });
    },

    savePhoto: function (photo) {
        return new Promise((resolve, reject) => {
            const tx = this.db.transaction("photos", "readwrite");
            const store = tx.objectStore("photos");
            store.put(photo);
            tx.oncomplete = () => resolve();
            tx.onerror = (e) => reject(e.target.error);
        });
    },

    getPhotosForInspection: function (inspectionId) {
        return new Promise((resolve, reject) => {
            const tx = this.db.transaction("photos", "readonly");
            const store = tx.objectStore("photos");
            const index = store.index("inspectionId");
            const request = index.getAll(inspectionId);
            request.onsuccess = () => resolve(request.result || []);
            request.onerror = (e) => reject(e.target.error);
        });
    },

    getPendingInspections: function () {
        return new Promise((resolve, reject) => {
            const tx = this.db.transaction("inspections", "readonly");
            const store = tx.objectStore("inspections");
            const request = store.getAll();
            request.onsuccess = () => {
                // Status enum: 0=Draft, 1=Completed, 2=Synced
                const pending = (request.result || []).filter(i => i.status === 1);
                resolve(pending);
            };
            request.onerror = (e) => reject(e.target.error);
        });
    }
};

