@inherits LayoutComponentBase
@inject ConnectivityService Connectivity
@inject NavigationManager Navigation
@implements IDisposable

<div class="app-header">
    <h1>🏗️ Site Inspector</h1>
    <span class="connectivity-dot @(isOnline ? "online" : "offline")" title="@(isOnline ? "Online" : "Offline")"></span>
</div>

@if (!isOnline)
{
    <div class="offline-banner">📡 Offline — data saved locally</div>
}

<div class="page-content">
    @Body
</div>

<nav class="bottom-nav">
    <a href="/" class="nav-item @NavClass("/")">
        <span class="icon">🏠</span>
        Home
    </a>
    <a href="/new" class="nav-item @NavClass("/new")">
        <span class="icon">➕</span>
        New
    </a>
    <a href="/history" class="nav-item @NavClass("/history")">
        <span class="icon">📋</span>
        History
    </a>
</nav>

@code {
    private bool isOnline = true;

    protected override async Task OnInitializedAsync()
    {
        await Connectivity.InitAsync();
        isOnline = Connectivity.IsOnline;
        Connectivity.OnConnectivityChanged += HandleConnectivityChange;
    }

    private void HandleConnectivityChange(bool online)
    {
        isOnline = online;
        InvokeAsync(StateHasChanged);
    }

    private string NavClass(string path)
    {
        var relativePath = Navigation.ToBaseRelativePath(Navigation.Uri);
        if (path == "/" && relativePath == "") return "active";
        if (path != "/" && ("/" + relativePath).StartsWith(path)) return "active";
        return "";
    }

    public void Dispose()
    {
        Connectivity.OnConnectivityChanged -= HandleConnectivityChange;
    }
}

