@code {
    private List<Inspection> recentInspections = new();
    private int pendingCount;
    private int totalCount;

    protected override async Task OnInitializedAsync()
    {
        var all = await Db.GetAllInspectionsAsync();
        totalCount = all.Count;
        pendingCount = all.Count(i => i.Status == InspectionStatus.Completed);
        recentInspections = all.OrderByDescending(i => i.CreatedAt).Take(10).ToList();
