@code {
    [Parameter] public Guid InspectionId { get; set; }

    private List<PhotoRecord> photos = new();
    private string currentPhotoBase64 = "";
    private string currentCaption = "";

    protected override async Task OnInitializedAsync()
    {
        photos = await Db.GetPhotosForInspectionAsync(InspectionId);
    }

    private async Task HandleFileSelected(InputFileChangeEventArgs e)
    {
        var file = e.File;
        if (file != null)
        {
            var buffer = new byte[file.Size];
            await file.OpenReadStream(maxAllowedSize: 10 * 1024 * 1024).ReadAsync(buffer);
            currentPhotoBase64 = $"data:{file.ContentType};base64,{Convert.ToBase64String(buffer)}";
            currentCaption = "";
        }
    }

    private async Task SavePhoto()
    {
        if (string.IsNullOrEmpty(currentPhotoBase64)) return;

        var photo = new PhotoRecord
        {
            Id = Guid.NewGuid(),
            InspectionId = InspectionId,
            Base64Data = currentPhotoBase64,
            Caption = currentCaption,
            TakenAt = DateTime.UtcNow
        };

        await Db.SavePhotoAsync(photo);
        photos.Add(photo);
        currentPhotoBase64 = "";
        currentCaption = "";
    }

    private void GoToSummary()
    {
        Navigation.NavigateTo($"/summary/{InspectionId}");
    }
}

@page "/summary/{InspectionId:guid}"
@inject IndexedDbService Db
@inject NavigationManager Navigation

@if (inspection == null)
