}
else
{
    <h2 style="margin-bottom:4px;">Inspection Summary</h2>
    <p style="color:var(--color-text-light);margin-bottom:16px;">@inspection.SiteName — @inspection.CreatedAt.ToString("MMM dd, yyyy HH:mm")</p>

    <div class="card mb-2">
        <p><strong>Inspector:</strong> @inspection.InspectorName</p>
        <p><strong>Status:</strong> <span class="badge badge-@inspection.Status.ToString().ToLower()">@inspection.Status</span></p>
    </div>

    @foreach (var category in inspection.ChecklistItems.GroupBy(i => i.Category))
    {
