+        inspection?.ChecklistItems.Where(i => i.Category == activeCategory).ToList() ?? new();
+
+    private int reviewedCount => inspection?.ChecklistItems.Count(i => i.IsCompliant != null || itemTouched.Contains(i.Id)) ?? 0;
+    private int totalCount => inspection?.ChecklistItems.Count ?? 0;
+    private double ProgressPercent => totalCount > 0 ? (double)reviewedCount / totalCount * 100 : 0;
+
+    protected override async Task OnInitializedAsync()
+    {
+        inspection = await Db.GetInspectionAsync(InspectionId);
+        if (inspection != null)
+        {
+            categories = inspection.ChecklistItems.Select(i => i.Category).Distinct().ToList();
+            if (categories.Any())
+            {
+                activeCategory = categories[0];
+            }
+        }
+    }
+
+    private void SetCategory(string category)
+    {
+        activeCategory = category;
+        categoryIndex = categories.IndexOf(category);
+    }
+
+    private async Task SetCompliance(ChecklistItem item, bool compliant)
+    {
+        item.IsCompliant = compliant;
+        itemTouched.Add(item.Id);
+        await SaveInspection();
+    }
+
+    private async Task SetNA(ChecklistItem item)
+    {
+        item.IsCompliant = null;
+        itemTouched.Add(item.Id);
+        await SaveInspection();
+    }
+
+    private async Task SetNotes(ChecklistItem item, string notes)
+    {
+        item.Notes = notes;
+        await SaveInspection();
+    }
+
+    private async Task SaveInspection()
+    {
+        if (inspection != null)
+        {
+            await Db.SaveInspectionAsync(inspection);
+        }
+    }
+
+    private void NextCategory()
+    {
+        if (categoryIndex < categories.Count - 1)
+        {
+            categoryIndex++;
+            activeCategory = categories[categoryIndex];
+        }
+    }
+
+    private void PrevCategory()
+    {
+        if (categoryIndex > 0)
+        {
+            categoryIndex--;
+            activeCategory = categories[categoryIndex];
+        }
+    }
+
+    private void GoToPhotos()
+    {
+        Navigation.NavigateTo($"/photos/{InspectionId}");
+    }
+}
+

