+@page "/summary/{InspectionId:guid}"
+@inject IndexedDbService Db
+@inject NavigationManager Navigation
+
+@if (inspection == null)
+{
+    <p>Loading...</p>
+}
+else
+{
+    <h2 style="margin-bottom:4px;">Inspection Summary</h2>
+    <p style="color:var(--color-text-light);margin-bottom:16px;">@inspection.SiteName — @inspection.CreatedAt.ToString("MMM dd, yyyy HH:mm")</p>
+
+    <div class="card mb-2">
+        <p><strong>Inspector:</strong> @inspection.InspectorName</p>
+        <p><strong>Status:</strong> <span class="badge badge-@inspection.Status.ToString().ToLower()">@inspection.Status</span></p>
+    </div>
+
+    @foreach (var category in inspection.ChecklistItems.GroupBy(i => i.Category))
+    {
+        <div class="summary-section">
+            <h3>@category.Key</h3>
+            @foreach (var item in category)
+            {
+                <div class="summary-item">
+                    <span class="icon">
+                        @if (item.IsCompliant == true) { <text>✅</text> }
+                        else if (item.IsCompliant == false) { <text>❌</text> }
+                        else { <text>⬜</text> }
+                    </span>
+                    <span>@item.Description</span>
+                </div>
+                @if (!string.IsNullOrEmpty(item.Notes))
+                {
+                    <div style="padding-left:32px;font-size:0.85rem;color:var(--color-text-light);margin-bottom:4px;">
+                        📝 @item.Notes
+                    </div>
+                }
+            }
+        </div>
+    }
+
+    @if (photos.Any())
+    {
+        <div class="summary-section">
+            <h3>Photos (@photos.Count)</h3>
+            <div class="photo-grid">
+                @foreach (var photo in photos)
+                {
+                    <div class="photo-thumb">
+                        <img src="@photo.Base64Data" alt="@photo.Caption" />
+                    </div>
+                }
+            </div>
+        </div>
+    }
+
+    <div class="form-group mt-3">
+        <label>Additional Notes</label>
+        <textarea class="form-control" @bind="inspection.Notes" placeholder="Any additional observations..."></textarea>
+    </div>
+
+    @if (inspection.Status == InspectionStatus.Draft)
+    {
+        <button class="btn btn-success btn-block btn-lg mt-2" @onclick="CompleteInspection">
+            ✓ Complete Inspection
+        </button>
+    }
+    else
+    {
+        <div class="card text-center mt-2" style="background:#d4edda;">
+            <p style="margin:0;color:#155724;font-weight:600;">✓ Inspection @(inspection.Status == InspectionStatus.Synced ? "synced" : "completed and queued for sync")</p>
+        </div>
+    }
+}
+
+@code {
+    [Parameter] public Guid InspectionId { get; set; }
+
+    private Inspection? inspection;
+    private List<PhotoRecord> photos = new();
+
+    protected override async Task OnInitializedAsync()
+    {
+        inspection = await Db.GetInspectionAsync(InspectionId);
+        photos = await Db.GetPhotosForInspectionAsync(InspectionId);
+    }
+
+    private async Task CompleteInspection()
+    {
+        if (inspection == null) return;
+        inspection.Status = InspectionStatus.Completed;
+        await Db.SaveInspectionAsync(inspection);
+        StateHasChanged();
+    }
+}
