+@page "/photos/{InspectionId:guid}"
+@inject IndexedDbService Db
+@inject NavigationManager Navigation
+@inject IJSRuntime JS
+
+<h2 style="margin-bottom:16px;">📷 Photos</h2>
+
+<label class="camera-btn">
+    📸 Take Photo or Choose File
+    <InputFile OnChange="HandleFileSelected" accept="image/*" capture="environment"
+               style="display:none;" />
+</label>
+
+@if (!string.IsNullOrEmpty(currentPhotoBase64))
+{
+    <div class="card mt-2">
+        <img src="@currentPhotoBase64" style="width:100%;border-radius:8px;margin-bottom:8px;" />
+        <div class="form-group" style="margin-bottom:8px;">
+            <input class="form-control" @bind="currentCaption" placeholder="Add a caption..." />
+        </div>
+        <button class="btn btn-success btn-block" @onclick="SavePhoto">Save Photo</button>
+    </div>
+}
+
+@if (photos.Any())
+{
+    <h3 style="font-size:0.9rem;color:var(--color-text-light);margin-top:16px;">Attached Photos (@photos.Count)</h3>
+    <div class="photo-grid">
+        @foreach (var photo in photos)
+        {
+            <div class="photo-thumb" title="@photo.Caption">
+                <img src="@photo.Base64Data" alt="@photo.Caption" />
+            </div>
+        }
+    </div>
+}
+
+<div style="margin-top:24px;">
+    <button class="btn btn-primary btn-block" @onclick="GoToSummary">Review Summary →</button>
+</div>
+
+@code {
+    [Parameter] public Guid InspectionId { get; set; }
+
+    private List<PhotoRecord> photos = new();
+    private string currentPhotoBase64 = "";
+    private string currentCaption = "";
+
+    protected override async Task OnInitializedAsync()
+    {
+        photos = await Db.GetPhotosForInspectionAsync(InspectionId);
+    }
+
+    private async Task HandleFileSelected(InputFileChangeEventArgs e)
+    {
+        var file = e.File;
+        if (file != null)
+        {
+            var buffer = new byte[file.Size];
+            await file.OpenReadStream(maxAllowedSize: 10 * 1024 * 1024).ReadAsync(buffer);
+            currentPhotoBase64 = $"data:{file.ContentType};base64,{Convert.ToBase64String(buffer)}";
+            currentCaption = "";
+        }
+    }
+
+    private async Task SavePhoto()
+    {
+        if (string.IsNullOrEmpty(currentPhotoBase64)) return;
+
+        var photo = new PhotoRecord
+        {
+            Id = Guid.NewGuid(),
+            InspectionId = InspectionId,
+            Base64Data = currentPhotoBase64,
+            Caption = currentCaption,
+            TakenAt = DateTime.UtcNow
+        };
+
+        await Db.SavePhotoAsync(photo);
+        photos.Add(photo);
+        currentPhotoBase64 = "";
+        currentCaption = "";
+    }
+
+    private void GoToSummary()
+    {
+        Navigation.NavigateTo($"/summary/{InspectionId}");
+    }
+}
+

